@import "tailwindcss";

@theme {
  /* palette (mined, ranked by usage) */
  --color-neutral-50: #ffffff;
  --color-neutral-100: #ececec;
  --color-neutral-400: #a9a9a9;
  --color-neutral-500: #808080;
  --color-neutral-800: #414141;
  --color-neutral-900: #232323;
  --color-neutral-950: #161616;
  --color-red: #e50914;
  --color-red-2: #eb3942;
  --color-green: #2bb871;
  --color-orange: #d89d31;
  --color-deep-blue: #050042;
  --color-red-3: #c11119;
  --color-red-4: #99161d;
  --color-blue: #465a7e;
  --color-deep-blue-2: #192247;
  --color-deep-red: #461518;
  --color-pink: #b82869;
  --color-red-5: #e00000;

  /* inferred semantic roles (each maps to a distinct mined value) */
  --color-canvas: #ffffff;
  --color-ink: #161616;
  --color-text-muted: #a9a9a9;
  --color-surface: #ececec;
  --color-hairline: #808080;
  --color-accent: #e50914;
  --color-accent-2: #eb3942;
  --color-accent-3: #2bb871;

  --font-sans: "Netflix Sans", ui-sans-serif, system-ui, sans-serif;

  --text-xs: 0.625rem;
  --text-sm: 0.8125rem;
  --text-base: 0.875rem;
  --text-lg: 1rem;
  --text-xl: 1.125rem;
  --text-2xl: 1.25rem;
  --text-3xl: 1.5rem;
  --text-4xl: 2rem;
  --text-5xl: 4rem;
  --text-6xl: 5rem;
  --text-7xl: 6.25rem;
  --text-8xl: 7.5rem;

  --font-weight-thin: 100;
  --font-weight-light: 300;
  --font-weight-normal: 400;
  --font-weight-medium: 500;
  --font-weight-bold: 700;
  --font-weight-black: 900;

  /* line-heights, sorted tight -> loose */
  --leading-none: 1;
  --leading-tight: 1.5;

  --radius-sm: 0.125rem;
  --radius-md: 0.5rem;
  --radius-lg: 1rem;

  /* shadows, sorted by blur */
  --shadow-sm: 0 0.25rem 0.5rem 0 rgba(0,0,0,0.8);

  --breakpoint-sm: 37.5rem;
  --breakpoint-md: 60rem;
  --breakpoint-lg: 80rem;
  --breakpoint-xl: 100rem;
  --breakpoint-2xl: 120rem;
  --breakpoint-3xl: 160rem;

  /* most-used spacing values on the source site (px): 2, 4, 7, 12, 16, 22, 24, 32, 36, 40, 80, 96 */
}

